&lt;h2 id=&quot;at-174470&quot; class=&quot;c-accordion__title js-accordion-controller&quot;&gt;Responsibilities&lt;/h2&gt;
&lt;div id=&quot;ac-174470&quot; class=&quot;c-accordion__content&quot;&gt;
